    n = len(nums)
    srt = sorted(nums)
    feasible = True
    for i in range(0, n, 3):
        if srt[i + 2] - srt[i] > k:
            feasible = False
            break
    if not feasible:
        return output == []
    if not isinstance(output, list) or len(output) != n // 3:
        return False
    from collections import Counter
    used = Counter()
    for grp in output:
        if not isinstance(grp, list) or len(grp) != 3:
            return False
        mx, mn = max(grp), min(grp)
        if mx - mn > k:
            return False
        for v in grp:
            used[v] += 1
    return used == Counter(nums)

