function validate(args, output) {
    const nums = args[0], k = args[1];
    const n = nums.length;
    const srt = nums.slice().sort((a, b) => a - b);
    let feasible = true;
    for (let i = 0; i < n; i += 3) {
        if (srt[i + 2] - srt[i] > k) { feasible = false; break; }
    }
    if (!feasible) return Array.isArray(output) && output.length === 0;
    if (!Array.isArray(output) || output.length !== Math.floor(n / 3)) return false;
    const used = new Map();
    for (const grp of output) {
        if (!Array.isArray(grp) || grp.length !== 3) return false;
        const mx = Math.max(...grp), mn = Math.min(...grp);
        if (mx - mn > k) return false;
        for (const v of grp) used.set(v, (used.get(v) || 0) + 1);
    }
    const expected = new Map();
    for (const v of nums) expected.set(v, (expected.get(v) || 0) + 1);
    if (used.size !== expected.size) return false;
    for (const [v, c] of expected) if (used.get(v) !== c) return false;
    return true;
}

