var divideArray = function(nums, k) {
    const srt = nums.slice().sort((a, b) => a - b);
    const n = srt.length;
    const res = [];
    for (let i = 0; i < n; i += 3) {
        const triplet = [srt[i], srt[i + 1], srt[i + 2]];
        if (triplet[2] - triplet[0] > k) return [];
        res.push(triplet);
    }
    res.sort((a, b) => {
        const m = Math.min(a.length, b.length);
        for (let j = 0; j < m; j++) if (a[j] !== b[j]) return a[j] - b[j];
        return a.length - b.length;
    });
    return res;
};
